function ChefWork(input) {
    const lines = input.trim().split('\n');
    const N = parseInt(lines[0]); // Number of workers
    const costs = lines[1].split(' ').map(Number); // Cost for each worker
    const types = lines[2].split(' ').map(Number); // Type of each worker

    let minTranslatorCost = Infinity;
    let minAuthorCost = Infinity;
    let minAuthorTranslatorCost = Infinity;

    // Iterate through each worker
    for (let i = 0; i < N; i++) {
        if (types[i] === 1) { // Translator
            minTranslatorCost = Math.min(minTranslatorCost, costs[i]);
        } else if (types[i] === 2) { // Author
            minAuthorCost = Math.min(minAuthorCost, costs[i]);
        } else { // Author-Translator
            minAuthorTranslatorCost = Math.min(minAuthorTranslatorCost, costs[i]);
        }
    }

    // Calculate the minimum total cost
    const minTotalCost = Math.min(minTranslatorCost + minAuthorCost, minAuthorTranslatorCost);

    console.log(minTotalCost); // Output the minimum total cost
}

process.stdin.setEncoding('utf8');
